#include <bits/stdc++.h>
#define int long long
using namespace std;
const int mod = 19260817;
int exgcd (int a, int b, int &x, int &y) {
	if (b == 0) {
		x = 1;
		y = 0;
		return a;
	}
	int g = exgcd (b, a % b, x, y);
	int t = x;
	x = y;
	y = t - a / b * y;
	return g;
}
int a, b, m, n, l, x, y;
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> a >> b >> m >> n >> l;
	int t1 = m - n;
	int t2 = l;
	int c = b - a;
	if (t1 < 0) {
		t1 = -t1;
		c = -c;
	}
	int g = exgcd (t1, t2, x, y);
	if (c % g != 0) {
		cout << "Impossible";
		return 0;
	}
	int x0 = x * c / g;
	cout << (x0 % (t2 / g) + t2 / g) % (t2 / g);
	return 0;
}
